// // This module handles up to 4 interrupt requests. It has inputs for each request (irq0, irq1, irq2, irq3) and a clock signal. Upon rising edge of the clock, it checks the status of the interrupts. If an interrupt is active, it sets the corresponding output (ack0, ack1, ack2, ack3) low and clears the interrupt request after acknowledging it. Only one interrupt can be handled at a time, with priority given to irq3, followed by irq2, irq1, and irq0.
module interrupt_controller(
    input wire clk,
    input wire irq0,
    input wire irq1,
    input wire irq2,
    input wire irq3,
    output reg ack0,
    output reg ack1,
    output reg ack2,
    output reg ack3
);
    always @(posedge clk) begin
        if (irq0) begin
            ack0 <= 1;
            ack1 <= 0;
            ack2 <= 0;
            ack3 <= 0;
        end else if (irq1) begin
            ack0 <= 0;
            ack1 <= 1;
            ack2 <= 0;
            ack3 <= 0;
        end else if (irq2) begin
            ack0 <= 0;
            ack1 <= 0;
            ack2 <= 1;
            ack3 <= 0;
        end else if (irq3) begin
            ack0 <= 0;
            ack1 <= 0;
            ack2 <= 0;
            ack3 <= 1;
        end else begin
            ack0 <= 0;
            ack1 <= 0;
            ack2 <= 0;
            ack3 <= 0;
        end
    end
endmodule
